[Form]
public class FWFTextBlockUsageEx extends FormRun
{
    #resAppl

    FormDesign                      formDesign;
    InventDimCtrl_Frm               inventDimFormSetup;
    FWFTextBlockTreeNav             treeNav;

    CustTable                       custTable;
    VendTable                       vendTable;
    ProjTable                       projTable;
    Common                          callerTable;
    DirPartyTable                   dirPartyTable;

    FWFTextBlockModule              module;
    FWFTextBlockAccountRelationType accountType;

    TableGroupAll                   accountCode;
    FWFTextBlockAccountRelation		accountRelation;

    QueryBuildRange                 blockCodeHeader;
    QueryBuildRange                 blockCodeLines;

    boolean                         isRelation;
    FieldId                         selectedDocumentFldId;

}

private str buildInventCustVendFilter(
    FormDataSource                  _dsUsage,
    FWFTextBlockAccountRelationType _accountType
)
{
    QueryBuildDataSource    qbds = _dsUsage.queryRun().query().dataSourceTable(tableNum(FWFTextBlockUsage));
    str                     filter;
    FWFTextBlockGroupAssign groupAssign;

    void addTableFilter(str _fieldStrCode, int _code, str _fieldStrRel, str _rel)
    {
        filter = '(' + this.relationFilter(_dsUsage, _fieldStrCode, _code, _fieldStrRel, _rel) + ' || ' + this.relationCodeAllFilter(_dsUsage, _fieldStrCode) + ')';
    }

    void addGroupFilter(str _fieldStrCode, str _fieldStrRel, str _rel)
    {
        if (_rel)
        {
            filter += ' || ' + this.relationFilter(_dsUsage, _fieldStrCode, any2int(TableGroupAll::GroupId), _fieldStrRel, _rel);
        }
    }

    qbds.findRange(fieldNum(FWFTextBlockUsage, AccountType)).value(queryValue(_accountType));
    switch (_accountType)
    {
        case FWFTextBlockAccountRelationType::Vend :
            [accountCode, accountRelation] = [TableGroupAll::Table, vendTable.AccountNum];
            addTableFilter(fieldStr(FWFTextBlockUsage, AccountCode), any2int(accountCode), fieldStr(FWFTextBlockUsage, AccountRelation), accountRelation);
            while select groupAssign where groupAssign.RefId == vendTable.AccountNum
            {
                addGroupFilter(fieldStr(FWFTextBlockUsage, AccountCode), fieldStr(FWFTextBlockUsage, AccountRelation), groupAssign.GroupId);
            }
            break;

        case FWFTextBlockAccountRelationType::Cust :
            [accountCode, accountRelation] = [TableGroupAll::Table, custTable.AccountNum];
            addTableFilter(fieldStr(FWFTextBlockUsage, AccountCode), any2int(accountCode), fieldStr(FWFTextBlockUsage, AccountRelation), accountRelation);
            while select groupAssign where groupAssign.RefId == custTable.AccountNum
            {
                addGroupFilter(fieldStr(FWFTextBlockUsage, AccountCode), fieldStr(FWFTextBlockUsage, AccountRelation), groupAssign.GroupId);
            }
            break;

        case FWFTextBlockAccountRelationType::Proj :
            [accountCode, accountRelation] = [TableGroupAll::Table, projTable.ProjId];
            addTableFilter(fieldStr(FWFTextBlockUsage, AccountCode), any2int(accountCode), fieldStr(FWFTextBlockUsage, AccountRelation), accountRelation);
            while select groupAssign where groupAssign.RefId == projTable.ProjId
            {
                addGroupFilter(fieldStr(FWFTextBlockUsage, AccountCode), fieldStr(FWFTextBlockUsage, AccountRelation), groupAssign.GroupId);
            }
            break;

        case FWFTextBlockAccountRelationType::Prod :
            if (custTable.AccountNum)
            {
                [accountCode, accountRelation] = [TableGroupAll::Table, custTable.AccountNum];
                addTableFilter(fieldStr(FWFTextBlockUsage, AccountCode), any2int(accountCode), fieldStr(FWFTextBlockUsage, AccountRelation), accountRelation);
                while select groupAssign where groupAssign.RefId == custTable.AccountNum
                {
                    addGroupFilter(fieldStr(FWFTextBlockUsage, AccountCode), fieldStr(FWFTextBlockUsage, AccountRelation), groupAssign.GroupId);
                }
            }
            else if (vendTable.AccountNum)
            {
                [accountCode, accountRelation] = [TableGroupAll::Table, vendTable.AccountNum];
                addTableFilter(fieldStr(FWFTextBlockUsage, AccountCode), any2int(accountCode), fieldStr(FWFTextBlockUsage, AccountRelation), accountRelation);
                while select groupAssign where groupAssign.RefId == vendTable.AccountNum
                {
                    addGroupFilter(fieldStr(FWFTextBlockUsage, AccountCode), fieldStr(FWFTextBlockUsage, AccountRelation), groupAssign.GroupId);
                }
            }
            else if (projTable.ProjId)
            {
                [accountCode, accountRelation] = [TableGroupAll::Table, projTable.ProjId];
                addTableFilter(fieldStr(FWFTextBlockUsage, AccountCode), any2int(accountCode), fieldStr(FWFTextBlockUsage, AccountRelation), accountRelation);
                while select groupAssign where groupAssign.RefId == projTable.ProjId
                {
                    addGroupFilter(fieldStr(FWFTextBlockUsage, AccountCode), fieldStr(FWFTextBlockUsage, AccountRelation), groupAssign.GroupId);
                }
            }
            break;
    }

    return filter ? '(' + filter + ')' : '';
}

public void clearInventDim()
{
    UsageLines.InventDimId = InventDim::inventDimIdBlank();

    inventDim.data(InventDim::find(UsageLines.InventDimId));
    inventDim_ds.setCurrent();
    inventDim_ds.refresh();
}

void enableRelationFields(
    FWFTextBlockUsage   _textBlockUsage
    )
{
    FormDataSource      fdsUsage = FormDataUtil::getFormDataSource(_textBlockUsage) as FormDataSource;

    if (_textBlockUsage.ItemCode == TableGroupAll::All)
    {
        fdsUsage.object(fieldNum(FWFTextBlockUsage, ItemRelation)).skip(true);
        fdsUsage.object(fieldNum(FWFTextBlockUsage, ItemRelation)).allowEdit(false);
    }
    else
    {
        fdsUsage.object(fieldNum(FWFTextBlockUsage, ItemRelation)).skip(false);
        fdsUsage.object(fieldNum(FWFTextBlockUsage, ItemRelation)).allowEdit(true);
    }

    if (_textBlockUsage.AccountCode == TableGroupAll::All)
    {
        fdsUsage.object(fieldNum(FWFTextBlockUsage, AccountRelation)).skip(true);
        fdsUsage.object(fieldNum(FWFTextBlockUsage, AccountRelation)).allowEdit(false);
    }
    else
    {
        fdsUsage.object(fieldNum(FWFTextBlockUsage, AccountRelation)).skip(false);
        fdsUsage.object(fieldNum(FWFTextBlockUsage, AccountRelation)).allowEdit(true);
    }
}

public void  init()
{
    super();

    treeNav = FWFTextBlockTreeNav::newTreeView(TreeDoc);

    element.initParameters();

    treeNav.createFilterRange(ParmHeader_ds.queryBuildDataSource());
    treeNav.createFilterRange(ParmLines_ds.queryBuildDataSource());

    element.updateDesignDim(InventDimFormDesignUpdate::Init);
    element.updateDesignForm();
}

void  initParameters()
{
    FWFTextBlockAccountFilterType   accountFilterType;
    ;
    UsageHeader_ds.query().dataSourceTable(tableNum(FWFTextBlockUsage)).clearRanges();
    UsageHeader_ds.query().dataSourceTable(tableNum(FWFTextBlockUsage)).clearDynalinks();

    UsageLines_ds.query().dataSourceTable(tableNum(FWFTextBlockUsage)).clearRanges();
    UsageLines_ds.query().dataSourceTable(tableNum(FWFTextBlockUsage)).clearDynalinks();

    if (element.args().record())
    {
        isRelation = true;
    }

    if (element.args().parmEnumType() == enumNum(FWFTextBlockAccountFilterType))
    {
        accountFilterType = element.args().parmEnum();
    }
    else
    {
        module = FWFTextBlockModule::ReleasedProduct;
    }

    if (element.args() && element.args().record())
    {
        callerTable = element.args().record();
    }

    accountCode = TableGroupAll::All;

    switch (callerTable.TableId)
    {
        case tableNum(CustTable) :
            custTable = element.args().record();
            break;

        case tableNum(VendTable) :
            vendTable = element.args().record();
            break;

        case tableNum(ProjTable) :
            projTable = element.args().record();
            break;

        case tableNum(DirPartyTable) :
            dirPartyTable   = element.args().record();

            select firstonly custTable
                where custTable.Party == dirPartyTable.RecId;

            select firstonly vendTable
                where vendTable.Party == dirPartyTable.RecId;

            if (custTable && !vendTable)
            {
                accountFilterType = FWFTextBlockAccountFilterType::Cust;
            }
            if (!custTable && vendTable)
            {
                accountFilterType = FWFTextBlockAccountFilterType::Vend;
            }
            break;
    }

    UsageHeader_ds.object(fieldNum(FWFTextBlockUsage, ItemCode)).visible(false);
    UsageHeader_ds.object(fieldNum(FWFTextBlockUsage, ItemRelation)).visible(false);

    UsageHeader_ds.object(fieldNum(FWFTextBlockUsage, AccountType)).visible(false);
    UsageLines_ds.object(fieldNum(FWFTextBlockUsage, AccountType)).visible(false);

    blockCodeHeader = UsageHeader_ds.query().dataSourceTable(tableNum(FWFTextBlockUsage)).addRange(fieldNum(FWFTextBlockUsage, AccountCode));
    blockCodeHeader.status(RangeStatus::Locked);

    blockCodeLines = UsageLines_ds.query().dataSourceTable(tableNum(FWFTextBlockUsage)).addRange(fieldNum(FWFTextBlockUsage, AccountCode));
    blockCodeLines.status(RangeStatus::Locked);

    UsageHeader_AccountRelation.label("@SYS22898");
    UsageLines_AccountRelation.label("@SYS22898");

    UsageHeader_ds.query().dataSourceTable(tableNum(FWFTextBlockUsage)).addRange(fieldNum(FWFTextBlockUsage, AccountType));
    UsageHeader_ds.query().dataSourceTable(tableNum(FWFTextBlockUsage)).addRange(fieldNum(FWFTextBlockUsage, ProductType)).value(queryValue(FWFTextBlockProductType::None));

    UsageLines_ds.query().dataSourceTable(tableNum(FWFTextBlockUsage)).addRange(fieldNum(FWFTextBlockUsage, AccountType));
    UsageLines_ds.query().dataSourceTable(tableNum(FWFTextBlockUsage)).addRange(fieldNum(FWFTextBlockUsage, ProductType)).value(queryValue(FWFTextBlockProductType::ReleasedProduct));

    treeNav.parmAccountTypeFilter(accountFilterType);
    treeNav.initTree();
    treeNav.redrawTree();

}

Object inventDimSetupObject()
{
    return inventDimFormSetup;
}

ItemId itemId()
{
    return UsageLines.itemId();
}

str relationCodeAllFilter(
    FormDataSource      _dsUsage,
    str                 _fieldStrCode
    )
{
    str     dsName      = _dsUsage.queryRun().query().dataSourceTable(tableNum(FWFTextBlockUsage)).name();
    return strFmt('(%1.%2==%3)', dsName, _fieldStrCode, any2int(TableGroupAll::All));
}

str relationFilter(
    FormDataSource  _dsUsage,
    str             _fieldStrCode,
    int             _code,
    str             _fieldStrRel,
    str             _rel
    )
{
    str     dsName      = _dsUsage.queryRun().query().dataSourceTable(tableNum(FWFTextBlockUsage)).name();

    return strFmt('((%1.%2==%3) && (%1.%4=="%5"))', dsName, _fieldStrCode, _code, _fieldStrRel, _rel ? queryValue(_rel) : '');
}

public void reSelect(
    FormDataSource                  _dsUsage,
    FormDataSource                  _dsParm,
    QueryBuildRange                 _blockCode,
    FWFTextBlockAccountRelationType _accountType
    )
{
    str filter;

    if (isRelation)
    {
        filter = this.buildInventCustVendFilter(_dsUsage, _accountType);
    }

    _blockCode.value(filter);

    treeNav.setFilterRange(_dsParm.queryBuildDataSource(), selectedDocumentFldId);

    _dsUsage.executeQuery();
    _dsUsage.queryRun().saveUserSetup(false);
    _dsUsage.refresh();
}

public void updateDesignCustVend()
{
    switch (accountType)
    {
        case FWFTextBlockAccountRelationType::Cust:
            module = FWFTextBlockModule::Customer;
            break;
        case FWFTextBlockAccountRelationType::Vend:
            module = FWFTextBlockModule::Supplier;
            break;

        case FWFTextBlockAccountRelationType::Prod:
            module = FWFTextBlockModule::Supplier;
            break;

        case FWFTextBlockAccountRelationType::Proj:
            module = FWFTextBlockModule::Supplier;
            break;
    }

    switch (module)
    {
        case FWFTextBlockModule::Customer:
            UsageHeader_AccountRelation.label("@SYS24704");
            UsageLines_AccountRelation.label("@SYS24704");
            break;

        case FWFTextBlockModule::Supplier:
            UsageHeader_AccountRelation.label("@SYS9455");
            UsageLines_AccountRelation.label("@SYS9455");
            break;

        case FWFTextBlockModule::ReleasedProduct:
            UsageHeader_AccountRelation.label("@SYS191447");
            UsageLines_AccountRelation.label("@SYS191447");
            break;

        case FWFTextBlockModule::Project:
            UsageHeader_AccountRelation.label("@SYS4534");
            UsageLines_AccountRelation.label("@SYS4534");
            break;
    }

}

void updateDesignDim(InventDimFormDesignUpdate mode)
{
    InventDimParm       inventDimParmVisible;
    InventDimParm       inventDimParmEnabled;
    InventDimParm       inventDimParmLocked;

    InventDimGroupSetup inventDimGroupSetup;

    inventTable         localInventTable = inventTable::find(UsageLines.ItemRelation);

    switch (mode)
    {
        case InventDimFormDesignUpdate::Init          :
        case InventDimFormDesignUpdate::LinkActive    :
            if (!inventDimFormSetup)
            {
                inventDimFormSetup  = InventDimCtrl::newFromForm(element);
            }
            inventDimFormSetup.parmSkipOnHandLookUp(true);

        case InventDimFormDesignUpdate::Active        :
        case InventDimFormDesignUpdate::FieldChange   :
            inventDimFormSetup.formActiveSetup();
            if (UsageLines.ItemCode == TableGroupAll::Table && UsageLines.ItemRelation)
            {
                //Diviating from the common pattern using InventDimGroupSetup::newItemId(....) to allow the form to load with incomplete dimension settings on the product.
                inventDimGroupSetup = InventDimGroupSetup::newDimensionGroups(localInventTable.productDimensionGroup(), 0, 0);
                inventDimGroupSetup.inventDimParmActive(inventDimParmEnabled);
            }
            else
            {
                inventDimParmEnabled.clear();
            }

            inventDimParmLocked.initNonProductDimAllGroups();

            inventDimParmLocked.InventSiteIdFlag = NoYes::No;
            inventDimParmEnabled.InventSiteIdFlag = NoYes::Yes;
            inventDimParmLocked.InventOwnerIdFlag_RU = NoYes::Yes;

            inventDimFormSetup.parmDimParmLockedRightClick(inventDimParmLocked);
            inventDimFormSetup.parmDimParmVisibleGrid(inventDimParmVisible);
            inventDimFormSetup.parmDimParmEnabled(inventDimParmEnabled);
            inventDimFormSetup.formSetControls(true);

            break;

        default :
            throw error(strFmt("@SYS54195",funcName()));
    }
}

public void updateDesignForm()
{
    FWFTextBlockUsage_Supplier.visible(module == FWFTextBlockModule::Supplier);
    FWFTextBlockUsage_Product_Supplier.visible(module == FWFTextBlockModule::Supplier);

    FWFTextBlockUsage_Customer.visible(module == FWFTextBlockModule::Customer);
    FWFTextBlockUsage_Product_Customer.visible(module == FWFTextBlockModule::Customer);
}

public FWFTextBlockUsage newTmpRecord()
{
    FWFTextBlockUsage       textBlockUsage;

    // BP deviation documented
    textBlockUsage.setTmp();

    textBlockUsage.initValue();

    textBlockUsage.AccountType       = accountType;
    textBlockUsage.ProductType       = FWFTextBlockProductType::None;
    textBlockUsage.AccountCode       = accountCode;
    textBlockUsage.AccountRelation   = accountRelation;
    textBlockUsage.ItemCode          = TableGroupAll::All;

    textBlockUsage.updateRelations();
    textBlockUsage.insert();

    return textBlockUsage;
}

public void create(boolean _append = false)
{
    Args         args;
    FormRun      formOption;

    // super(_append);

    if (! selectedDocumentFldId)
    {
        return;
    }

    args = new Args();
    args.name(formStr(FWFTextBlockOptions));
    args.caller(element);
    args.parmEnumType(enumNum(AccessType));
    args.parmEnum(AccessType::Add);
    args.record(this.newTmpRecord());
    args.parm(int2str(selectedDocumentFldId));

    formOption = classfactory.formRunClass(args);
    formOption.init();
    formOption.run();
    formOption.wait();

    formOption.closeOk();

    if (FormDataUtil::getFormDataSource(UsageHeader))
    {
        UsageHeader_ds.executeQuery();
    }
}

public void delete()
{
    if (! UsageHeader.RecId)
    {
        super();
    }
    else
    {
        ttsBegin;

        if (ParmHeader.RecId && selectedDocumentFldId > 0)
        {
            ParmHeader.(selectedDocumentFldId) = false;
            ParmHeader.update();
        }

        ttsCommit;

        UsageHeader_ds.executeQuery();
    }
}

