public void write()
{
    UsageLines.InventDimId   = InventDim::findOrCreate(inventDim).InventDimId;
    UsageLines.SetupRefRefId = ParmLines.RecId;

    super();

    if (UsageLines.InventDimId != inventDim.InventDimId)
    {
        inventDim.data(InventDim::find(UsageLines.InventDimId));
        inventDim_ds.setCurrent();
    }
}

