public void selectionChanged(FormTreeItem _OldItem, FormTreeItem _NewItem, FormTreeSelect _how)
{
    int         idx;

    super(_OldItem, _NewItem, _how);

    [accountType, selectedDocumentFldId] = [accountType, 0];

    if (_NewItem != null)
    {
        idx = any2int(_NewItem.data());
        if (idx != 0)
        {
            [accountType, selectedDocumentFldId] = treeNav.getModule(idx);
        }
    }

    element.updateDesignCustVend();

    element.reSelect(UsageHeader_ds, ParmHeader_ds, blockCodeHeader, accountType);
    element.reSelect(UsageLines_ds, ParmLines_ds, blockCodeLines, accountType);
}
